  <text x="20" y="28" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Bitcoin vs S&amp;P 500 — Prêmio de Risco de Variância</text>
  <text x="20" y="46" fill="#9ca3af" font-size="13" font-family="sans-serif">Análise de 7M de cotações de opções da Deribit, 2019-2020 (Alexander &amp; Imeraj, 2019)</text>
  <rect x="20" y="70" width="320" height="140" rx="10" fill="#18181b" stroke="#27272a"/>
  <text x="180" y="135" fill="#f7931a" font-size="34" font-weight="700" font-family="sans-serif" text-anchor="middle">0,72</text>
  <text x="180" y="165" fill="#d4d4d8" font-size="14" font-family="sans-serif" text-anchor="middle">Variância neutra ao risco anualizada precificada nas opções</text>
  <rect x="360" y="70" width="320" height="140" rx="10" fill="#18181b" stroke="#27272a"/>
  <text x="520" y="135" fill="#60a5fa" font-size="34" font-weight="700" font-family="sans-serif" text-anchor="middle">0,58</text>
  <text x="520" y="165" fill="#d4d4d8" font-size="14" font-family="sans-serif" text-anchor="middle">Variância física anualizada efetivamente realizada</text>
  <rect x="20" y="230" width="320" height="140" rx="10" fill="#18181b" stroke="#27272a"/>
